import type {
  ScaleLinear,
  ScaleLogarithmic,
  ScaleSymLog,
  ScaleTime,
} from 'd3-scale';


import { AreaIndicator } from './AreaIndicator.js';
import { LineIndicator } from './LineIndicator.js';
import { useCurrentTheme } from '../../../../../../core/hooks/useCurrentTheme.js';
import { BrightnessFilter } from '../../../BrightnessFilter.js';
import { useGridPlotSize } from '../../../chart-grid/hooks/useGridPlotSize.js';
import { MarkerInteractionState } from '../../types/marker.js';
import { getMarkerBrightnessBasedOnState } from '../../utils/get-marker-brightness-based-on-state.js';
import { isRangeMarker } from '../../utils/is-range-marker.js';
import { serializeMarkerRange } from '../../utils/serialize-marker-range.js';

export interface IndicatorsRendererProps {
  start: Date | number;
  end?: Date | number;
  color: string;
  state: MarkerInteractionState;
  trackIndex: number;
  isInverted?: boolean;
  scale:
    | ScaleTime<number, number>
    | ScaleLinear<number, number>
    | ScaleLogarithmic<number, number>
    | ScaleSymLog<number, number>;
}

export const IndicatorsRenderer = ({
  start,
  end,
  color,
  state,
  trackIndex,
  scale,
  isInverted = false,
}: IndicatorsRendererProps) => {
  const { height } = useGridPlotSize();
  const theme = useCurrentTheme();
  const slope = getMarkerBrightnessBasedOnState(theme, state);
  let ShapeComponent;

  const brightnessFilterId = `brightness_${serializeMarkerRange(
    {
      start: start.valueOf(),
      end: end ? end.valueOf() : undefined,
    },
    trackIndex,
  )}`;

  const filter = `url(#${brightnessFilterId})`;

  const range = { start, end };

  if (isRangeMarker(range)) {
    const x0 = scale(isInverted ? range.end : range.start) ?? 0;
    const x1 = scale(isInverted ? range.start : range.end) ?? 0;
    const width = x1 - x0;
    ShapeComponent = AreaIndicator({
      x: x0,
      width,
      height,
      color,
      filter,
    });
  } else {
    const x0 = scale(range.start) ?? 0;
    ShapeComponent = LineIndicator({ x: x0, height, color, filter });
  }

  return (
    <>
      <BrightnessFilter id={brightnessFilterId} slope={slope} />
      {ShapeComponent}
    </>
  );
};
